using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _sut = new ShoppingCart();
    }

    // --- AddItem Tests ---

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _sut.AddItem("SKU-001", 1, 9.99m);

        var total = _sut.CalculateTotal();

        Assert.AreEqual(9.99m, total);
    }

    [TestMethod]
    public void AddItem_MultipleQuantity_MultipliesPrice()
    {
        _sut.AddItem("SKU-001", 3, 10.00m);

        var total = _sut.CalculateTotal();

        Assert.AreEqual(30.00m, total);
    }

    [TestMethod]
    public void AddItem_MultipleDifferentItems_SumsAll()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-002", 2, 5.00m);

        var total = _sut.CalculateTotal();

        Assert.AreEqual(20.00m, total);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_AccumulatesQuantity()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);
        _sut.AddItem("SKU-001", 2, 10.00m);

        var total = _sut.CalculateTotal();

        Assert.AreEqual(30.00m, total);
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    public void AddItem_InvalidQuantity_ThrowsArgumentException(int quantity)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.AddItem("SKU-001", quantity, 10.00m));
    }

    [TestMethod]
    [DataRow(0.0)]
    [DataRow(-5.0)]
    public void AddItem_InvalidPrice_ThrowsArgumentException(double price)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.AddItem("SKU-001", 1, (decimal)price));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void AddItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.AddItem(sku!, 1, 10.00m));
    }

    // --- RemoveItem Tests ---

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("SKU-001", 2, 15.00m);
        _sut.AddItem("SKU-002", 1, 5.00m);

        _sut.RemoveItem("SKU-001");

        var total = _sut.CalculateTotal();
        Assert.AreEqual(5.00m, total);
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_CartBecomesEmpty()
    {
        _sut.AddItem("SKU-001", 1, 10.00m);

        _sut.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.RemoveItem("DOES-NOT-EXIST"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void RemoveItem_NullOrEmptySku_ThrowsArgumentException(string? sku)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.RemoveItem(sku!));
    }

    // --- CalculateTotal Tests ---

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        var total = _sut.CalculateTotal();

        Assert.AreEqual(0m, total);
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _sut.AddItem("SKU-001", 1, 25.00m);
        _sut.AddItem("SKU-002", 2, 10.00m);
        _sut.RemoveItem("SKU-001");

        var total = _sut.CalculateTotal();

        Assert.AreEqual(20.00m, total);
    }

    // --- ApplyCoupon Tests ---

    [TestMethod]
    [DataRow("SAVE10", 10.00)]
    [DataRow("SAVE20", 20.00)]
    public void ApplyCoupon_ValidCode_ReducesTotal(string code, double discount)
    {
        _sut.AddItem("SKU-001", 1, 100.00m);

        _sut.ApplyCoupon(code);

        var total = _sut.CalculateTotal();
        Assert.AreEqual(100.00m - (decimal)discount, total);
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        _sut.AddItem("SKU-001", 1, 50.00m);

        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon("INVALID"));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentException(string? code)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _sut.ApplyCoupon(code!));
    }

    [TestMethod]
    public void ApplyCoupon_DiscountExceedsTotal_TotalIsZero()
    {
        _sut.AddItem("SKU-001", 1, 5.00m);

        _sut.ApplyCoupon("SAVE10");

        var total = _sut.CalculateTotal();
        Assert.IsTrue(total >= 0m, "Total should never be negative");
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(
            () => _sut.ApplyCoupon("SAVE10"));
    }
}

